from spyne import Application, rpc, ServiceBase, Iterable, Integer, Unicode, Decimal, DateTime
from spyne.protocol.soap import Soap11
from spyne.server.wsgi import WsgiApplication
from spyne.model.complex import ComplexModel
from spyne.model.primitive import String, Integer as SpyneInteger
from datetime import datetime
import logging

# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# Define data models
class AccountInfo(ComplexModel):
    account_id = Integer
    account_holder = Unicode
    balance = Decimal
    created_date = DateTime

class TransferRequest(ComplexModel):
    from_account = Integer
    to_account = Integer
    amount = Decimal

class TransferResponse(ComplexModel):
    success = Boolean
    message = Unicode
    balance_after = Decimal

# Mock database
accounts_db = {
    1: {"account_holder": "John Doe", "balance": Decimal("1000.00")},
    2: {"account_holder": "Jane Smith", "balance": Decimal("1500.00")},
    3: {"account_holder": "Bob Johnson", "balance": Decimal("2000.00")}
}

class FinancialServices(ServiceBase):
    @rpc(SpyneInteger, _returns=AccountInfo)
    def getAccountInfo(ctx, account_id):
        logger.info(f"Getting account info for account {account_id}")
        if account_id not in accounts_db:
            raise Exception(f"Account {account_id} not found")
        
        account_data = accounts_db[account_id]
        return AccountInfo(
            account_id=account_id,
            account_holder=account_data["account_holder"],
            balance=account_data["balance"],
            created_date=datetime.now()
        )

    @rpc(SpyneInteger, _returns=Decimal)
    def getBalance(ctx, account_id):
        logger.info(f"Getting balance for account {account_id}")
        if account_id not in accounts_db:
            raise Exception(f"Account {account_id} not found")
        
        return accounts_db[account_id]["balance"]

    @rpc(TransferRequest, _returns=TransferResponse)
    def transferFunds(ctx, transfer_request):
        logger.info(f"Processing transfer from {transfer_request.from_account} to {transfer_request.to_account}")
        
        # Validate accounts exist
        if transfer_request.from_account not in accounts_db:
            raise Exception(f"Source account {transfer_request.from_account} not found")
        if transfer_request.to_account not in accounts_db:
            raise Exception(f"Destination account {transfer_request.to_account} not found")
        
        # Check sufficient funds
        from_balance = accounts_db[transfer_request.from_account]["balance"]
        if from_balance < transfer_request.amount:
            raise Exception("Insufficient funds")
        
        # Perform transfer
        accounts_db[transfer_request.from_account]["balance"] -= transfer_request.amount
        accounts_db[transfer_request.to_account]["balance"] += transfer_request.amount
        
        return TransferResponse(
            success=True,
            message="Transfer completed successfully",
            balance_after=accounts_db[transfer_request.from_account]["balance"]
        )

# Create application
application = Application([FinancialServices], 
                         tns='http://financialservices.com/',
                         in_protocol=Soap11(validator='lxml'),
                         out_protocol=Soap11())

# Create WSGI application
wsgi_app = WsgiApplication(application)

